INSERT INTO `destinations` (`id`, `name`, `slug`, `country`, `region`, `region_type`, `description`, `latitude`, `longitude`, `featured_image`, `created_at`) VALUES (1, 'Maasai Mara National Reserve', 'maasai-mara-national-reserve', 'Kenya', 'East Africa', 'National Reserve', '<p>The Maasai Mara is one of the most famous and important wildlife conservation and wilderness areas in Africa, world-renowned for its exceptional populations of lion, African leopard, cheetah and African bush elephant.</p>', -1.48946900, 35.10144500, 'destinations/23940cf9-346f-49b8-837f-f86099587a3d.jpeg', '2026-06-03 23:37:34') ON DUPLICATE KEY UPDATE `name`=VALUES(`name`), `slug`=VALUES(`slug`), `country`=VALUES(`country`), `region`=VALUES(`region`), `region_type`=VALUES(`region_type`), `description`=VALUES(`description`), `latitude`=VALUES(`latitude`), `longitude`=VALUES(`longitude`), `featured_image`=VALUES(`featured_image`);
INSERT INTO `destinations` (`id`, `name`, `slug`, `country`, `region`, `region_type`, `description`, `latitude`, `longitude`, `featured_image`, `created_at`) VALUES (2, 'Amboseli National Park', 'amboseli-national-park', 'Kenya', 'East Africa', 'National Park', '<p>Crowned by Mount Kilimanjaro, Africa\'s highest peak, the Amboseli National Park is one of Kenya\'s most popular parks. The name \"Amboseli\" comes from a Maasai word meaning \"salty dust\". It is the best place in the world to get close to free-ranging elephants.</p>', -2.65271600, 37.25607800, 'destinations/eab8dd2b-1ba4-4049-aa20-af104d1f0132.jpg', '2026-06-03 23:37:34') ON DUPLICATE KEY UPDATE `name`=VALUES(`name`), `slug`=VALUES(`slug`), `country`=VALUES(`country`), `region`=VALUES(`region`), `region_type`=VALUES(`region_type`), `description`=VALUES(`description`), `latitude`=VALUES(`latitude`), `longitude`=VALUES(`longitude`), `featured_image`=VALUES(`featured_image`);
INSERT INTO `destinations` (`id`, `name`, `slug`, `country`, `region`, `region_type`, `description`, `latitude`, `longitude`, `featured_image`, `created_at`) VALUES (3, 'Tsavo East National Park', 'tsavo-east-national-park', 'Kenya', 'East Africa', 'National Park', '<p>Tsavo East is one of the oldest and largest parks in Kenya. Known for its vast elephant herds covered in red dust, it offers a raw and untamed wilderness experience.</p>', -2.43197400, 38.51768200, 'destinations/1908d61a-1067-423c-a901-8f370c046f7d.jpg', '2026-06-03 23:37:34') ON DUPLICATE KEY UPDATE `name`=VALUES(`name`), `slug`=VALUES(`slug`), `country`=VALUES(`country`), `region`=VALUES(`region`), `region_type`=VALUES(`region_type`), `description`=VALUES(`description`), `latitude`=VALUES(`latitude`), `longitude`=VALUES(`longitude`), `featured_image`=VALUES(`featured_image`);
