INSERT INTO `destinations` (`id`, `name`, `slug`, `country`, `region`, `region_type`, `description`, `latitude`, `longitude`, `featured_image`, `created_at`) VALUES (6, 'Ngorongoro Crater', 'ngorongoro-crater', 'Tanzania', 'East Africa', 'Conservation Area', NULL, -3.17407600, 35.58700300, 'destinations/c44813c2-70a9-48f7-9635-3869637a7b2f.jpg', '2026-06-03 23:37:34') ON DUPLICATE KEY UPDATE `name`=VALUES(`name`), `slug`=VALUES(`slug`), `country`=VALUES(`country`), `region`=VALUES(`region`), `region_type`=VALUES(`region_type`), `description`=VALUES(`description`), `latitude`=VALUES(`latitude`), `longitude`=VALUES(`longitude`), `featured_image`=VALUES(`featured_image`);
INSERT INTO `destinations` (`id`, `name`, `slug`, `country`, `region`, `region_type`, `description`, `latitude`, `longitude`, `featured_image`, `created_at`) VALUES (7, 'Zanzibar Island', 'zanzibar-island', 'Tanzania', 'East Africa', 'Island', '<p>Zanzibar is a Tanzanian archipelago off the coast of East Africa. It is characterized by beautiful sandy beaches with fringing coral reefs, and the historic Stone Town.</p>', -6.16534600, 39.20268800, 'destinations/15931c2d-4224-4bee-a17f-f5edf47acba0.jpg', '2026-06-03 23:37:34') ON DUPLICATE KEY UPDATE `name`=VALUES(`name`), `slug`=VALUES(`slug`), `country`=VALUES(`country`), `region`=VALUES(`region`), `region_type`=VALUES(`region_type`), `description`=VALUES(`description`), `latitude`=VALUES(`latitude`), `longitude`=VALUES(`longitude`), `featured_image`=VALUES(`featured_image`);
INSERT INTO `destinations` (`id`, `name`, `slug`, `country`, `region`, `region_type`, `description`, `latitude`, `longitude`, `featured_image`, `created_at`) VALUES (8, 'Diani Beach', 'diani-beach', 'Kenya', 'East Africa', 'Beach', '<p>Diani Beach is a major beach on the Indian Ocean coast of Kenya. It is renowned for its flawless, long stretch of white-sand beach hugged by lush forest and kissed by surfable waves.</p>', -4.27686200, 39.59430200, 'destinations/bd0035ff-0235-47da-837a-979cbc909e0f.jpg', '2026-06-03 23:37:34') ON DUPLICATE KEY UPDATE `name`=VALUES(`name`), `slug`=VALUES(`slug`), `country`=VALUES(`country`), `region`=VALUES(`region`), `region_type`=VALUES(`region_type`), `description`=VALUES(`description`), `latitude`=VALUES(`latitude`), `longitude`=VALUES(`longitude`), `featured_image`=VALUES(`featured_image`);
INSERT INTO `destinations` (`id`, `name`, `slug`, `country`, `region`, `region_type`, `description`, `latitude`, `longitude`, `featured_image`, `created_at`) VALUES (9, 'Nairobi', 'nairobi', 'Kenya', 'East Africa', 'City', '<p>Nairobi is Kenya\'s capital city. In addition to its urban core, the city has Nairobi National Park, a large game reserve known for breeding endangered black rhinos and home to giraffes, zebras and lions.</p>', -1.28633300, 36.81721700, 'destinations/2825d3b6-6656-4b70-bbf5-d6e16cc6195f.jpg', '2026-06-03 23:37:34') ON DUPLICATE KEY UPDATE `name`=VALUES(`name`), `slug`=VALUES(`slug`), `country`=VALUES(`country`), `region`=VALUES(`region`), `region_type`=VALUES(`region_type`), `description`=VALUES(`description`), `latitude`=VALUES(`latitude`), `longitude`=VALUES(`longitude`), `featured_image`=VALUES(`featured_image`);
